//
//  DeviceContainer.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 04.09.2025.
//

import Foundation
import FactoryKit

extension Container {
    /// Текущее устройство, использовать только во View!
    var deviceContainer: Factory<DeviceContainer> { self { DeviceContainer() }.singleton }
}

@Observable
final class DeviceContainer {

    private let userDefaults = UserDefaults.standard

    private enum Consts {
        static let lastSavedDeviceIdKey = "SavedRadiaCodeDevice"
    }

    typealias RadiaCodeDeviceId = String

    var current: BluetoothDevice?

    func isDifferentDevice(_ deviceIdentifier: String) -> Bool {
        guard let currentId = current?.radiacode.identifier else { return false }
        return currentId != deviceIdentifier
    }

    @ObservationIgnored
    var lastSavedDeviceId: RadiaCodeDeviceId? {
        get {
            userDefaults.string(forKey: Consts.lastSavedDeviceIdKey)
        }
        set {
            if let value = newValue {
                userDefaults.set(value, forKey: Consts.lastSavedDeviceIdKey)
            } else {
                userDefaults.removeObject(forKey: Consts.lastSavedDeviceIdKey)
            }
        }
    }
}

