//  RadiaCode
//
//  Created by Matvey Kozin on 19.02.2025.
//

import Foundation
import FactoryKit

protocol SpectrumCalibrationListUseCase {

    func getSpectrums() async -> [Spectrum]
}

final class SpectrumCalibrationListUseCaseImpl: SpectrumCalibrationListUseCase {

    @Injected(\.spectrumRepository) var repository
    @Injected(\.deviceManager) private var deviceManager

    func getSpectrums() async -> [Spectrum] {
        guard let currentDevice = deviceManager.connectedDevice, let coefficients = currentDevice.spectrumSettings.coefficients else { return []}
        return await repository.getSpectrums(by: currentDevice.identifier, coefficients: [coefficients.a0, coefficients.a1, coefficients.a2], areSameCoefficients: false)
    }
}

