8	import Foundation
9	import Observation
10	import Combine
11	import FactoryKit
12	import SwiftUI
13	
14	@Observable
15	final class ActiveFoodAnalysisViewModel {
16	    
17	    @ObservationIgnored
18	    @AppStorage("FoodAnalysisOptionsCompletion") private var completion: FoodAnalysisOptions.Completion = .stop
19	    
20	    @ObservationIgnored
21	    @Injected(\.activityDataRepository) private var activityDataRepository
22	    
23	    @ObservationIgnored
24	    @Injected(\.deviceConnectionManager) private var deviceConnectionManager
25	    
26	    @ObservationIgnored
27	    @Injected(\.deviceManager) private var deviceManager
28	    
29	    @ObservationIgnored
30	    var foodContaminationSourceDataViewModel: FoodContaminationSourceDataViewModel = .init()
31	    
32	    var activeFoodAnalysis: FoodAnalysis? {
33	        didSet {
34	            if oldValue?.resultState == .unknown && activeFoodAnalysis?.resultState != .unknown {
35	                if completion == .stop {
36	                    pause()
37	                }
38	                analysisFinished = true
39	            }
40	        }
41	    }
42	    
43	    var openActiveAnalysis = false
44	    var reloadAnalysis = true
45	    var analysisFinished = false
46	    var deviceIsReady = false
47	    var showDifferentDeviceAlerrt = false
48	    var spectrumDisabled = false
49	
50	    private let activeFoodAnalysisUseCase: ActiveFoodAnalysisUseCase = ActiveFoodAnalysisUseCaseImpl()
51	    private let updateFoodAnalysisUseCase: UpdateFoodAnalysisUseCase = UpdateFoodAnalysisUseCaseImpl()
52	    
53	    @ObservationIgnored
54	    private var cancellable: Set<AnyCancellable> = .init()
55	    @ObservationIgnored
56	    private var activeAnalysisCancellable: AnyCancellable?
57	    @ObservationIgnored
58	    private var resumeAnalysisCancellable: AnyCancellable?
59	    
60	    private let queue = DispatchQueue(label: "com.radiacode.activityFood")
61	    
62	    init() {
63	        Task {
64	            if let activeFoodAnalysis = await activeFoodAnalysisUseCase.getActiveFoodAnalysis() {
65	                self.activeFoodAnalysis = activeFoodAnalysis
66	                if activeFoodAnalysis.activityState == .analyzing {
67	                    activityDataSubscription()
68	                }
69	            }
70	            connectedDeviceSubscription()
71	        }
72	        
73	        foodContaminationSourceDataViewModel.analysisCreatedPublisher
74	            .sink {  [weak self] sourceData in
75	                guard let self else { return }
76	                Task {
77	                    self.activityDataRepository.cancelSpectrumCollect()
78	                    
79	                    self.activeAnalysisCancellable?.cancel()
80	                    self.activeAnalysisCancellable = nil
81	                    self.analysisFinished = false
82	                    
83	                    if let activeFoodAnalysis = self.activeFoodAnalysis {
84	                        await self.updateFoodAnalysisUseCase.stop(analysis: activeFoodAnalysis)
85	                        self.reloadAnalysis = true
86	                    }
87	                    
88	                    self.activityDataRepository.startSpectrumCollect()
89	                    
90	                    guard let spectrumData = await self.awaitFirstSpectrum() else { return }
91	                    guard let device = self.deviceManager.connectedDevice?.radiacode else { return }
92	                    
93	                    self.activeFoodAnalysis = await self.activeFoodAnalysisUseCase.createActiveAnalysis(
94	                        sourceData: sourceData,
95	                        startSpectrum: spectrumData,
96	                        device: device
97	                    )
98	                    
99	                    self.activityDataSubscription()
100	
101	                    await MainActor.run {
102	                        self.openActiveAnalysis = true
103	                    }
104	
105	                }
106	            }
107	            .store(in: &cancellable)
108	    }
109	    
110	    private func activityDataSubscription() {
111	        activeAnalysisCancellable?.cancel()
112	        activeAnalysisCancellable = activityDataRepository.spectrumSubject
113	            .receive(on: DispatchQueue.main)
114	            .sink { [weak self] spectrumData in
115	                guard let self, let activeFoodAnalysis = self.activeFoodAnalysis else { return }
116	                self.updateFoodAnalysisUseCase.updateSampleData(analysis: activeFoodAnalysis, sampleData: spectrumData)
117	            }
118	    }
119	    
120	    private func connectedDeviceSubscription() {
121	        deviceConnectionManager.connectionSubject
122	            .receive(on: DispatchQueue.main)
123	            .sink { [weak self] state in
124	                guard let self else { return }
125	                self.deviceIsReady = state.isReady
126	                guard case .ready(let device) = state else { return }
127	                self.spectrumDisabled = device.spectrumDisabled
128	                guard self.activeFoodAnalysis?.activityState == .analyzing, self.activeFoodAnalysis?.device == device.radiacode else { return }
129	                self.activityDataRepository.startSpectrumCollect()
130	            }
131	            .store(in: &cancellable)
132	    }
133	    
134	    func pause() {
135	        activityDataRepository.cancelSpectrumCollect()
136	        activeAnalysisCancellable?.cancel()
137	        activeAnalysisCancellable = nil
138	        if let activeFoodAnalysis {
139	            updateFoodAnalysisUseCase.pause(analysis: activeFoodAnalysis)
140	        }
141	    }
142	    
143	    func resume(analysis: FoodAnalysis) async {
