//
//  ActiveFoodAnalysisViewModel.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 30.05.2025.
//

import Foundation
import Observation
import Combine
import FactoryKit
import SwiftUI

@Observable
final class ActiveFoodAnalysisViewModel {

    @ObservationIgnored
    @AppStorage("FoodAnalysisOptionsCompletion") private var completion: FoodAnalysisOptions.Completion = .stop

    @ObservationIgnored
    @Injected(\.activityDataRepository) private var activityDataRepository

    @ObservationIgnored
    @Injected(\.deviceConnectionManager) private var deviceConnectionManager

    @ObservationIgnored
    @Injected(\.deviceManager) private var deviceManager

    @ObservationIgnored
    var foodContaminationSourceDataViewModel: FoodContaminationSourceDataViewModel = .init()

    var activeFoodAnalysis: FoodAnalysis? {
        didSet {
            if oldValue?.resultState == .unknown && activeFoodAnalysis?.resultState != .unknown {
                if completion == .stop {
                    pause()
                }
                analysisFinished = true
            }
        }
    }

    var openActiveAnalysis = false
    var reloadAnalysis = true
    var analysisFinished = false
    var deviceIsReady = false
    var showDifferentDeviceAlerrt = false
    var spectrumDisabled = false

    private let activeFoodAnalysisUseCase: ActiveFoodAnalysisUseCase = ActiveFoodAnalysisUseCaseImpl()
    private let updateFoodAnalysisUseCase: UpdateFoodAnalysisUseCase = UpdateFoodAnalysisUseCaseImpl()

    @ObservationIgnored
    private var cancellable: Set<AnyCancellable> = .init()
    @ObservationIgnored
    private var activeAnalysisCancellable: AnyCancellable?
    @ObservationIgnored
    private var resumeAnalysisCancellable: AnyCancellable?

    private let queue = DispatchQueue(label: "com.radiacode.activityFood")

    init() {
        Task {
            if let activeFoodAnalysis = await activeFoodAnalysisUseCase.getActiveFoodAnalysis() {
                self.activeFoodAnalysis = activeFoodAnalysis
                if activeFoodAnalysis.activityState == .analyzing {
                    activityDataSubscription()
                }
            }
            connectedDeviceSubscription()
        }

        foodContaminationSourceDataViewModel.analysisCreatedPublisher
            .sink {  [weak self] sourceData in
                guard let self else { return }
                Task {
                    self.activityDataRepository.cancelSpectrumCollect()

                    self.activeAnalysisCancellable?.cancel()
                    self.activeAnalysisCancellable = nil
                    self.analysisFinished = false

                    if let activeFoodAnalysis = self.activeFoodAnalysis {
                        await self.updateFoodAnalysisUseCase.stop(analysis: activeFoodAnalysis)
                        self.reloadAnalysis = true
                    }

                    self.activityDataRepository.startSpectrumCollect()

                    guard let spectrumData = await self.awaitFirstSpectrum() else { return }
                    guard let device = self.deviceManager.connectedDevice?.radiacode else { return }

                    self.activeFoodAnalysis = await self.activeFoodAnalysisUseCase.createActiveAnalysis(
                        sourceData: sourceData,
                        startSpectrum: spectrumData,
                        device: device
                    )

                    self.activityDataSubscription()

                    await MainActor.run {
                        self.openActiveAnalysis = true
                    }

                }
            }
            .store(in: &cancellable)
    }

    private func activityDataSubscription() {
        activeAnalysisCancellable?.cancel()
        activeAnalysisCancellable = activityDataRepository.spectrumSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] spectrumData in
                guard let self, let activeFoodAnalysis = self.activeFoodAnalysis else { return }
                self.updateFoodAnalysisUseCase.updateSampleData(analysis: activeFoodAnalysis, sampleData: spectrumData)
            }
    }

    private func connectedDeviceSubscription() {
        deviceConnectionManager.connectionSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self else { return }
                self.deviceIsReady = state.isReady
                guard case .ready(let device) = state else { return }
                self.spectrumDisabled = device.spectrumDisabled
                guard self.activeFoodAnalysis?.activityState == .analyzing, self.activeFoodAnalysis?.device == device.radiacode else { return }
                self.activityDataRepository.startSpectrumCollect()
            }
            .store(in: &cancellable)
    }

    func pause() {
        activityDataRepository.cancelSpectrumCollect()
        activeAnalysisCancellable?.cancel()
        activeAnalysisCancellable = nil
        if let activeFoodAnalysis {
            updateFoodAnalysisUseCase.pause(analysis: activeFoodAnalysis)
        }
    }

    func resume(analysis: FoodAnalysis) async {
        // Попытка запуска набора на другом устройстве
        guard deviceManager.connectedDevice?.radiacode == analysis.device else {
            showDifferentDeviceAlerrt = true
            return
        }

        if let activeFoodAnalysis, analysis != activeFoodAnalysis {
            await updateFoodAnalysisUseCase.stop(analysis: activeFoodAnalysis)
        }
        await updateFoodAnalysisUseCase.resume(analysis: analysis)

        await MainActor.run {
            activeFoodAnalysis = analysis
            reloadAnalysis = true
        }

        activityDataRepository.startSpectrumCollect()

        guard let spectrumData = await awaitFirstSpectrum() else { return }
        await self.updateFoodAnalysisUseCase.updateStartData(analysis: analysis, startData: spectrumData)

        activityDataSubscription()
    }

    private func awaitFirstSpectrum() async -> SpectrumData? {
        var iterator = activityDataRepository.spectrumSubject.values.makeAsyncIterator()
        return await iterator.next()
    }

    @MainActor
    func removeActiveAnalysis() async {
        activityDataRepository.cancelSpectrumCollect()
        activeAnalysisCancellable?.cancel()
        activeAnalysisCancellable = nil
        activeFoodAnalysis = nil
        if let analysis = await activeFoodAnalysisUseCase.getFirstNonActiveAnalysis() {
            await updateFoodAnalysisUseCase.active(analysis: analysis)
            activeFoodAnalysis = analysis
        }
    }
}

extension Container {

    var activeFoodAnalysisViewModel: Factory<ActiveFoodAnalysisViewModel> {
        self { ActiveFoodAnalysisViewModel() }
            .singleton
    }
}

