protocol SpectrumUpdateCoefficientsUseCase {

    /// Обновление коэффицентов
    /// - Parameters:
    ///   - coefficients: коэффиценты
    ///   - spectrum: спектр
    func updateCoefficientsFromDevice(to spectrum: Spectrum)
}

final class SpectrumUpdateCoefficientsUseCaseImpl: SpectrumUpdateCoefficientsUseCase {

    @Injected(\.spectrumRepository) private var spectrumRepository
    @Injected(\.deviceManager) private var deviceManager

    func updateCoefficientsFromDevice(to spectrum: Spectrum) {
        guard let coefficients = deviceManager.connectedDevice?.spectrumSettings.coefficients else { return }
        spectrum.updateCoefficients(coefficients)
        Task {
            await spectrumRepository.update(.coefficients(coefficients), spectrumId: spectrum.id)
        }
    }
}

