    @Published var calibrationToDeviceAvailable: Bool = false
    @Published var calibrationToSpectrumAvailable: Bool = false
    @Published var options: SpectrumOptionsProvider

    let title: String
    let spectrumChartViewModel: SpectrumChartViewModel
    let spectrum: Spectrum

    private let updateUseCase: SpectrumUpdateCoefficientsUseCase = SpectrumUpdateCoefficientsUseCaseImpl()

    init(spectrum: Spectrum, backgroundSpectrum: Spectrum? = nil) {
        let options: SpectrumOptionsProvider
        if let backgroundSpectrum {
            options = SpectrumLocalOptionsProvider(backgroundSpectrum: backgroundSpectrum)
        } else {
            options = Container.shared.spectrumGlobalOptions()
        }
        self.options = options
        self.spectrumChartViewModel = .init(spectrum: spectrum, spectrumOptionsProvider: options)
        self.title = spectrum.title
        self.spectrum = spectrum

        self.setAsBackgroundAvailable = options.backgroundSpectrum?.id != spectrum.id
        updateCalibrationAvailability()
    }

    func exportSpectrum() throws -> URL {
        try spectrum.asXml().exportURL
    }

    func setSpectrumAsBackground() {
        options.backgroundSpectrum = spectrum
        setAsBackgroundAvailable = false
    }

    func applyNewCalibrationToDevice() async {
        await deviceSetupManager.setupCalibrationSettings(.new(spectrum.data.coefficients))
        updateCalibrationAvailability()
    }

    func applyNewCalibrationToSpectrum() {
        updateUseCase.updateCoefficientsFromDevice(to: spectrum)
        updateCalibrationAvailability()
    }

    func updateCalibrationAvailability() {
        guard let apply = deviceManager.connectedDevice?.applyCoefficentsAvailable(for: spectrum) else { return }
        Task { @MainActor in
            self.calibrationToDeviceAvailable = apply.toDevice
            self.calibrationToSpectrumAvailable = apply.toSpectrum
        }
    }
}

