import Foundation
import Combine
import FactoryKit

final class SignalizationViewModel: ObservableObject {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.dataBufferRepository) private var dataBufferRepository
    @LazyInjected(\.hapticManager) private var hapticManager

    @Published var signalizationTime: Date? = nil
    @Published var showSignalizationAlarm: Bool = false {
        didSet {
            if showSignalizationAlarm {
                hapticManager.play(pattern: .signalization)
            } else {
                hapticManager.stop()
            }
        }
    }

    @Published var countRateViewModel: RadiationLevelViewModel
    @Published var doseRateViewModel: RadiationLevelViewModel

    private var cancellable: Set<AnyCancellable> = .init()

    init(countRateViewModel: RadiationLevelViewModel, doseRateViewModel: RadiationLevelViewModel) {
        self.countRateViewModel = countRateViewModel
        self.doseRateViewModel = doseRateViewModel

        countRateViewModel
            .objectWillChange
            .sink { [weak self] _ in
                self?.objectWillChange.send()
            }
            .store(in: &cancellable)

        doseRateViewModel
            .objectWillChange
            .sink { [weak self] _ in
                self?.objectWillChange.send()
            }
            .store(in: &cancellable)

        dataBufferRepository.eventPublisher
            .filter (\.id.isAlarm)
            .filter { !$0.isOld }
            .receive(on: DispatchQueue.main)
            .sink { [weak self] event in
                guard let self = self, self.deviceManager.connectedDevice?.settings.alarm == true else { return }
                if !event.time.isActiveDate {
                    if self.countRateViewModel.level == .normal && self.doseRateViewModel.level == .normal {
                        return
                    }
                }

                if signalizationTime == nil {
                    signalizationTime = Date(timeIntervalSince1970: event.time)
                }
                if showSignalizationAlarm == false {
                    showSignalizationAlarm = true
                }
            }
            .store(in: &cancellable)
    }

    @MainActor
    func turnOffSignalization() async {
        await deviceManager.send(command: PlaySignalCommand(action: .stop))
        signalizationTime = nil
        showSignalizationAlarm = false
    }
}

