//  SpectrogramViewModel.swift
//  Radiacode
//
//  Created by Matvey Kozin on 03.04.2024.
//

import Combine
import FactoryKit
import SwiftUI

@Observable
final class SpectrogramViewModel {

    enum Consts {
        static let maxSpectrogramSize: Int = 21600
        static let spectrogramOffsetSize: Int = 1000
    }

    typealias Interrupt = SpectrogramModel.Interrupt

    @ObservationIgnored
    @AppStorage("SpectrogramOptionsStartAccumulation") private var startAccumulation: SpectrogramOptions.StartAccumulation = .auto

    @ObservationIgnored
    @AppStorage("SpectrogramTimeLimitApproach") private var limit: SpectrogramOptions.TimeLimitApproach = .cyclic

    @ObservationIgnored
    @AppStorage("onPause") private var onPause: Bool = false

    @ObservationIgnored
    @Injected(\.spectrogramDataRepository) private var spectrogramDataRepository
    @ObservationIgnored
    @Injected(\.deviceConnectionManager) private var deviceConnectionManager
    @ObservationIgnored
    @Injected(\.deviceManager) private var deviceManager

    enum State {
        case notStarted
        case inProgress
        case pause
    }

    var deviceIsReady = false
    var spectrumDisabled = false
    var secondsElapsed: UInt32 = 0
    var state: State = .notStarted
    var spectrumDetection = true
    var delay: Double = 4.0
    var spectrogramChartViewModel: SpectrogramChartViewModel?
    var differentDevice = false
    var showMismatchAlert = false

    @ObservationIgnored
    private var timerDate: Date = .now
    @ObservationIgnored
    private var timer: Timer?
    @ObservationIgnored
    private var savedTime: UInt32 = 0
    @ObservationIgnored
    private var interrupt: SpectrogramModel.Interrupt?
    @ObservationIgnored
    private var cancellable: Set<AnyCancellable> = .init()
    @ObservationIgnored
    private var spectrumCancellable: Set<AnyCancellable> = .init()

    private let queue = DispatchQueue(label: "com.radiacode.spectrogram")
    private let spectrogramCreateUseCase: SpectrogramSaveUseCase = SpectrogramSaveUseCaseImpl()
    private let spectrogramGetUseCase: SpectrogramGetUseCase = SpectrogramGetUseCaseImpl()
    private let spectrogramUpdateUseCase: SpectrogramUpdateUseCase = SpectrogramUpdateUseCaseImpl()

    init() {
        Task {
            if let spectrogram = await self.spectrogramGetUseCase.getActiveSpectrogram() {
                self.spectrogramChartViewModel = SpectrogramChartViewModel(spectrogram: spectrogram)
                self.state = .pause
                self.interrupt = onPause ? .manual : .unexpected
                self.savedTime = spectrogram.diffSpectrums.fullCollectTime
                self.secondsElapsed = self.savedTime
            }
            mainSubscriptions()
        }
    }

    func mainSubscriptions() {
        deviceConnectionManager.connectionSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self = self else { return }
                self.deviceIsReady = state.isReady
                switch state {
                case .ready(let device):
                    self.spectrumDisabled = device.spectrumDisabled
                    if let spectrogramChartViewModel = self.spectrogramChartViewModel {
                        // Если была запущена спектрограмма на другом устройстве RC
                        self.differentDevice = spectrogramChartViewModel.spectrogram.deviceIdentifier != device.identifier
                    }
                    guard !self.differentDevice, !self.onPause else { return }
                    // Запуск спектрограммы в случае прерывания
                    if self.state == .pause && self.interrupt == .unexpected {
                        self.resumeSpectrogram()
                    } else if self.state == .notStarted && self.startAccumulation == .auto {
                        self.startSpectrogram()
                    }                    
                default:
                    if self.state == .inProgress {
                        Task { @MainActor in
                            self.pauseSpectrogram(.unexpected)
                        }
                    }
                }
            }
            .store(in: &cancellable)
    }

    func spectrumSubscriptions() {
        spectrogramDataRepository.spectrumAccumSubject
            .filter { _ in self.spectrogramChartViewModel == nil }
            .receive(on: queue)
            .sink { [weak self] mainSpectrum in
                guard let self = self, let radiacode = self.deviceManager.connectedDevice?.radiacode else { return }
                Task {
                    let spectrogram = await self.spectrogramCreateUseCase.createActiveSpectrogram(radiacode: radiacode, spectrum: mainSpectrum)
                    await MainActor.run {
                        self.spectrogramChartViewModel = .init(spectrogram: spectrogram)
                        self.interrupt = nil
                    }
                }
            }
            .store(in: &spectrumCancellable)

        spectrogramDataRepository.spectrumDiffSubject
            .receive(on: queue)
            .removeDuplicates()
            .sink { [weak self] spectrum in
                guard let self = self, let spectrogramChartViewModel else { return }
                Task { @MainActor in
                    let spectr = spectrogramChartViewModel.appendSpectrum(spectrum, interrupt: self.interrupt)
                    self.spectrogramUpdateUseCase.appendSpectrum(spectrogram: spectrogramChartViewModel.spectrogram, spectrum: spectr)
                    self.interrupt = nil

                    if spectrogramChartViewModel.spectrogram.diffSpectrums.count > Consts.maxSpectrogramSize + Consts.spectrogramOffsetSize {
                        switch self.limit {
                        case .cyclic:
                            self.spectrogramUpdateUseCase.removeFirstSpectrum(spectrogram: spectrogramChartViewModel.spectrogram, count: Consts.spectrogramOffsetSize)
                            spectrogramChartViewModel.removeFirstSpectrum(Consts.spectrogramOffsetSize)
                        case .new:
                            self.startNewDeviceSpectrogram()
                        }
                    }

                    self.savedTime = spectrogramChartViewModel.spectrogram.diffSpectrums.fullCollectTime
                    self.timerDate = .now
                }
            }
            .store(in: &spectrumCancellable)
    }

    func play() {
        guard !differentDevice else {
            showMismatchAlert = true
            return
        }

        onPause = false

        if state == .notStarted {
            startSpectrogram()
        } else if state == .pause {
            resumeSpectrogram()
        }
    }

    @MainActor
    func startNewDeviceSpectrogram() {
        differentDevice = false
        stopSpectrogram()
        startSpectrogram()
    }

    private func startSpectrogram() {
        state = .inProgress
        spectrogramDataRepository.setupDelaySpectrumDiff(delay)
        Task {
            do {
                try await startReceiving()
            } catch {
                await stopSpectrogram()
            }
        }
    }

    private func resumeSpectrogram() {
        guard interrupt != nil else { return }
        state = .inProgress
        Task {
            do {
                try await startReceiving()
            }
            catch {
                await pauseSpectrogram(.unexpected)
            }
        }
    }

    @MainActor
    private func startReceiving() async throws {
        startTimer(startTime: Date.now)
        spectrumSubscriptions()
        try await spectrogramDataRepository.startSpectrogram()
    }

    @MainActor
    func pauseSpectrogram(_ interrupt: Interrupt) {
        state = .pause

        self.interrupt = interrupt
        stopReceiving()
        savedTime = secondsElapsed

        if interrupt == .manual {
            onPause = true
        }
    }

    @MainActor
    func stopSpectrogram() {
        state = .notStarted

        stopReceiving()
        savedTime = 0
        secondsElapsed = 0
        differentDevice = false
        interrupt = nil

        if let spectrogramId = spectrogramChartViewModel?.spectrogram.id {
            spectrogramUpdateUseCase.finishSpectrogram(spectrogramId)
        }
        spectrogramChartViewModel = nil
    }

    func spectrogramSaveModel() -> SpectrogramSaveModel? {
        deviceManager.cancelRealTimeData()
        guard let spectrogramChartViewModel else { return nil }
        return .init(
            spectrogram: spectrogramChartViewModel.spectrogram,
            time: secondsElapsed,
            detection: spectrumDetection ? spectrogramChartViewModel.getSpectrumDetectionLimit() : nil
        )
    }

    @MainActor
    private func startTimer(startTime: Date) {
        self.timerDate = startTime
        timer?.invalidate()
        self.timer = Timer(every: 1.0) { [weak self] in
            guard let self else { return }
            let delta = Date.now.timeIntervalSince(self.timerDate)
            let clamped = max(0, delta)
            self.secondsElapsed = self.savedTime &+ UInt32(clamped)
        }
    }

    @MainActor
    private func stopReceiving() {
        spectrumCancellable.removeAll()
        spectrogramDataRepository.cancelSpectrogram()
        timer?.invalidate()
        timer = nil
    }
}

