//
//  FirmwareUpdateService.swift
//  Radiacode
//
//  Created by Андрей Левчик on 23.12.2023.
//

import Foundation
import Combine
import FactoryKit

/// Сервис обновления прошивки прибора
protocol FirmwareUpdateService {

    /// Прогресс загрузки
    var progress: PassthroughSubject<FirmwareUpdateServiceImpl.State, Never> { get }

    /// Получает последнюю доступную прошивку для прибора и необходимость обновления
    /// - Parameters:
    ///   - deviceSignature: Сигнатура подключённого устройства
    /// - Returns: кортеж: `version` – номер версии; `needUpdate` –  необходимость обновления прошивки
    func lastestVersion(for deviceSignature: FirmwareCommand.ReadFlashSiganture.Response) throws -> (version: String, needUpdate: Bool)

    /// Старт обновления прошивки прибора
    func startUpdate() async
}

final class FirmwareUpdateServiceImpl: FirmwareUpdateService {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.firmwareFactory) private var firmwareFactory

    /// Состояние обновления прошивки
    enum State: Equatable {
        /// Начальное
        case initial
        /// Прогресс в 0..1
        case inProgress(Double)
        /// Ошибка
        case error(Error)
        /// Начало установки
        case install
        /// Конец установки
        case finish(String)

        var isLoading: Bool {
            switch self {
            case .initial, .finish, .error:
                return false
            case .inProgress, .install:
                return true
            }
        }

        static func == (lhs: FirmwareUpdateServiceImpl.State, rhs: FirmwareUpdateServiceImpl.State) -> Bool {
            switch (lhs, rhs) {
            case (.initial, .initial):
                return true
            case (.install, .install):
                return true
            case (.finish(let lhsVersion), .finish(let rhsVersion)):
                return lhsVersion == rhsVersion
            case (.inProgress(let lhsProgress), .inProgress(let rhsProgress)):
                return lhsProgress == rhsProgress
            case (.error(let lhsError), .error(let rhsError)):
                return lhsError.localizedDescription == rhsError.localizedDescription
            default:
