    private var firmwareDTO: FirmwareDTO?

    func lastestVersion(for deviceSignature: FirmwareCommand.ReadFlashSiganture.Response) throws -> (version: String, needUpdate: Bool) {
        let firmware = try firmwareFactory.getFirmware(for: deviceSignature)
        let needUpdate = firmware.signature > deviceSignature.signature
