            throw FirmwareUpdateError.updateFirmware
        }

        guard updateResponse.updateValidStatus == 0 else {
            throw FirmwareUpdateError.updateFirmewareCode(updateResponse.updateValidStatus)
        }   
    }

    private func writeFirmware(
        device: BluetoothDevice,
        signaure: UInt32,
        offset: UInt32,
