import Foundation
import Combine
import FactoryKit

/// Сервис обновления прошивки прибора
protocol FirmwareUpdateService {

    /// Прогресс загрузки
    var progress: PassthroughSubject<FirmwareUpdateServiceImpl.State, Never> { get }

    /// Получает последнюю доступную прошивку для прибора и необходимость обновления
    /// - Parameters:
    ///   - deviceSignature: Сигнатура подключённого устройства
    /// - Returns: кортеж: `version` – номер версии; `needUpdate` –  необходимость обновления прошивки
    func lastestVersion(for deviceSignature: FirmwareCommand.ReadFlashSiganture.Response) throws -> (version: String, needUpdate: Bool)

    /// Старт обновления прошивки прибора
    func startUpdate() async
}

final class FirmwareUpdateServiceImpl: FirmwareUpdateService {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceContainer) private var deviceContainer
    @Injected(\.firmwareFactory) private var firmwareFactory

    /// Состояние обновления прошивки
    enum State: Equatable {
        /// Начальное
        case initial
        /// Прогресс в 0..1
        case inProgress(Double)
        /// Ошибка
        case error(Error)
        /// Начало установки
        case install
        /// Конец установки
        case finish(String)

        var isLoading: Bool {
            switch self {
            case .initial, .finish, .error:
                return false
            case .inProgress, .install:
                return true
            }
        }

        static func == (lhs: FirmwareUpdateServiceImpl.State, rhs: FirmwareUpdateServiceImpl.State) -> Bool {
            switch (lhs, rhs) {
            case (.initial, .initial):
                return true
            case (.install, .install):
                return true
            case (.finish(let lhsVersion), .finish(let rhsVersion)):
                return lhsVersion == rhsVersion
            case (.inProgress(let lhsProgress), .inProgress(let rhsProgress)):
                return lhsProgress == rhsProgress
            case (.error(let lhsError), .error(let rhsError)):
                return lhsError.localizedDescription == rhsError.localizedDescription
            default:
                return false
            }
        }
    }

    enum FirmwareUpdateError: Error {
        case nonDevice
        case nonDeviceSignature
        case nonFirmwareData
        case getInfo
        case writeFirmeware
        case writeFirmewareCode(UInt32)
        case updateFirmware
        case updateFirmewareCode(UInt32)
    }

    let progress: PassthroughSubject<State, Never> = .init()

    private var firmwareDTO: FirmwareDTO?

    func lastestVersion(for deviceSignature: FirmwareCommand.ReadFlashSiganture.Response) throws -> (version: String, needUpdate: Bool) {
        let firmware = try firmwareFactory.getFirmware(for: deviceSignature)
        let needUpdate = firmware.signature > deviceSignature.signature
        if needUpdate {
            self.firmwareDTO = firmware
        }
        return (firmware.version, needUpdate)
    }

    func startUpdate() async {
        do {
            try await updateDevice()
        } catch {
            deviceManager.startRealTimeData()
            progress.send(.error(error))
        }
    }

    private func updateDevice() async throws {
        guard let device = deviceManager.connectedDevice else {
            throw FirmwareUpdateError.nonDevice
        }
        let firmware: FirmwareDTO
        if let firmwareDTO {
            firmware = firmwareDTO
        } else {
            guard let signature = device.firmware.signature else {
                throw FirmwareUpdateError.nonDeviceSignature
            }
            firmware = try firmwareFactory.getFirmware(for: signature)
        }

        deviceManager.cancelRealTimeData()

        let getInfoResult = await device.send(command: FirmwareCommand.Image.GetInfo())
        guard case .success(let getInfoResponse) = getInfoResult else {
            throw FirmwareUpdateError.getInfo
        }

        var diseredBlockSize = getInfoResponse.diseredBlockSize

        /// Началом загрузки прошивки во внешнюю память считается подача команды со смещением OFFSET == 0
        var offset: UInt32 = 0
        if let deviceSignature = getInfoResponse.signature, deviceSignature == firmware.signature {
            offset = getInfoResponse.loadedBytes
        }

        let fullPackageSize = firmware.package.count
        var firmwareLenghtSize = UInt32(firmware.package.count)

        /// Если по каким-то причинам в прошивку записалось больше данных чем неоходимо
        /// Повторяем процесс
        if offset > firmwareLenghtSize {
            offset = 0
        } else {
            firmwareLenghtSize -= offset
            if firmwareLenghtSize < diseredBlockSize {
                diseredBlockSize = firmwareLenghtSize
            }
        }

        while firmwareLenghtSize > 0 {
            progress.send(.inProgress(Double(offset) / Double(fullPackageSize)))
            try await writeFirmware(
                device: device,
                signaure: firmware.signature,
                offset: offset,
                lenght: diseredBlockSize,
                data: Array(firmware.package[safe: Int(offset)..<Int(offset + diseredBlockSize)])
            )

            firmwareLenghtSize -= diseredBlockSize
            offset += diseredBlockSize

            if firmwareLenghtSize < diseredBlockSize {
                diseredBlockSize = firmwareLenghtSize
