            /// Завершением загрузки считается подача команды с параметром LENGTH == 0, при этом данные уже не передаются.
            if firmwareLenghtSize == 0 {
                try await writeFirmware(
                    device: device,
                    signaure: firmware.signature,
                    offset: offset,
                    lenght: 0,
                    data: []
                )
            }
        }

        progress.send(.install)
        let updateResult = await device.send(command: FirmwareCommand.Image.Update(
            info: .init(siganture: firmware.signature)
        ))

        guard case .success(let updateResponse) = updateResult else {
            throw FirmwareUpdateError.updateFirmware
        }

        guard updateResponse.updateValidStatus == 0 else {
            throw FirmwareUpdateError.updateFirmewareCode(updateResponse.updateValidStatus)
        }   
    }

    private func writeFirmware(
        device: BluetoothDevice,
        signaure: UInt32,
        offset: UInt32,
        lenght: UInt32,
        data: [UInt8]
    ) async throws(FirmwareUpdateError)  {
        let writeResult = await device.send(command: FirmwareCommand.Image.Write(
            info: .init(
                siganture: signaure,
                offset: offset,
                lenght: lenght,
                data: data
            )
        ))

        guard case .success(let writeResponse) = writeResult else {
